+                    if cell.bg != currentBg {
+                        currentBg = cell.bg
+                        if let bg = cell.bg {
+                            if bg & 0xFF00_0000 != 0 {
+                                let red = (bg >> 16) & 0xFF
+                                let green = (bg >> 8) & 0xFF
+                                let blue = bg & 0xFF
+                                output += "\u{001B}[48;2;\(red);\(green);\(blue)m"
+                            } else if bg <= 255 {
